messages.content:
Extract data from the following document based on the JSON schema.
Return null if the document does not contain information relevant to schema.
Return only the JSON with no explanation text.
The JSON schema is as follows:
{
  "type": "object",
  "title": "FY2019 Demographic Data",
  "required": [
    "worldwideAssociates",
    "leadershipGenderBreakdown"
  ],
  "properties": {
    "worldwideAssociates": {
      "type": "object",
      "required": [
        "total",
        "menPct",
        "womenPct",
        "notDisclosedPct"
      ],
      "properties": {
        "total": {
          "type": "number",
          "description": "Total number of worldwide associates reported"
        },
        "menPct": {
          "type": "number",
          "description": "Decimal representation of the percentage of men"
        },
        "womenPct": {
          "type": "number",
          "description": "Decimal representation of the percentage of women"
        },
        "notDisclosedPct": {
          "type": "number",
          "description": "Decimal representation of the percentage of associates who did not disclose gender"
        }
      }
    },
    "leadershipGenderBreakdown": {
      "type": "array",
      "items": {
        "type": "object",
        "required": [
          "group",
          "men",
          "women"
        ],
        "properties": {
          "men": {
            "type": "number",
            "description": "Number of men in this leadership group"
          },
          "group": {
            "type": "string",
            "description": "Name of the leadership group (e.g., 'Board of Directors')"
          },
          "women": {
            "type": "number",
            "description": "Number of women in this leadership group"
          }
        }
      },
      "description": "Gender breakdown for board of directors and executive officers"
    }
  }
}
